SELECT classification_name 
FROM crime_classifications 
WHERE classification_id = 1;

SELECT SUM(adult_count) AS total_adult_arrests
FROM adult_arrests
WHERE classification_id = 1 AND year_id = 1;

SELECT cc.classification_name, ja.juvenile_count
FROM juvenile_arrests ja
JOIN crime_classifications cc ON ja.classification_id = cc.classification_id;

SELECT classification_id, SUM(juvenile_count) AS total_juvenile_arrests
FROM juvenile_arrests
GROUP BY classification_id;

SELECT SUM(total_arrests) AS total_arrests
FROM (
    SELECT SUM(juvenile_count) AS total_arrests FROM juvenile_arrests
    UNION ALL
    SELECT SUM(adult_count) AS total_arrests FROM adult_arrests
) AS combined_arrests;

SELECT classification_name, COUNT(*) AS total_entries 
FROM crime_classifications 
LIMIT 1;

SELECT SUM(juvenile_count) AS total_juvenile_arrests
FROM juvenile_arrests
WHERE classification_id = 1;

SELECT year_id, SUM(juvenile_count) AS total_juvenile_arrests
FROM juvenile_arrests
GROUP BY year_id;

SELECT year_id, SUM(adult_count) AS total_adult_arrests
FROM adult_arrests
GROUP BY year_id;

SELECT sex, age_group, ethnicity, total
FROM demographics
ORDER BY total DESC;
